window.AIESS = window.AIESS || {}; AIESS.questions = AIESS.questions || [];
AIESS.questions.push(
  { id:"D3-001", domain:3, obj:"3.1", diff:"easy", q:"Why can a generative AI chatbot give an answer that sounds totally confident but is completely wrong?", options:["It always copies answers word for word from a trusted encyclopedia","It refuses to answer unless it has checked an official source","It predicts the most likely next words rather than looking up verified facts","It only responds when it is 100% certain the answer is correct"], answer:2, explain:"<strong>It predicts the most likely next words rather than looking up verified facts</strong> is why the tool can be confidently wrong: it generates fluent, plausible text from patterns with no built-in awareness of whether the content is true.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It always copies answers word for word from a trusted encyclopedia</b>: the model generates new text from patterns, it does not quote one verified encyclopedia.</span><span class='qd'><b>It refuses to answer unless it has checked an official source</b>: the model answers without checking any source, which is exactly why errors slip through.</span><span class='qd'><b>It only responds when it is 100% certain the answer is correct</b>: the model has no true certainty about facts and responds regardless, so confidence is not a sign of accuracy.</span>" },
  { id:"D3-002", domain:3, obj:"3.2", diff:"medium", q:"You ask an AI for last quarter's revenue for a specific public company and it returns exact numbers. What is the single BEST first step before trusting them?", options:["Cross-check the numbers against the company's official financial report","Ask the AI the same question again to see if it repeats the numbers","Copy the numbers into your report because the AI is usually right","Assume they are wrong and discard them without checking"], answer:0, explain:"<strong>Cross-check the numbers against the company's official financial report</strong> is best because specific, high-stakes figures are exactly what AI can fabricate, so you confirm against an authoritative primary source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask the AI the same question again to see if it repeats the numbers</b>: repeating the question may just repeat the same confident error and is not an independent check.</span><span class='qd'><b>Copy the numbers into your report because the AI is usually right</b>: trusting unverified figures for a report risks spreading fabricated data.</span><span class='qd'><b>Assume they are wrong and discard them without checking</b>: discarding without verifying wastes potentially correct data and still involves no real check.</span>" },
  { id:"D3-003", domain:3, obj:"3.3", diff:"hard", q:"A team notices their AI-assisted reports all read the same: smooth, wordy, and forgettable, with no unique insight. What is the BEST description of the root problem and its fix?", options:["Generic 'slop' from vague prompts; fix by prompting with specific data, angle, and audience","The reports are too short; make each one much longer","The font is wrong; change the font for a fresh look","The AI is broken; stop using AI for reports entirely"], answer:0, explain:"<strong>Generic 'slop' from vague prompts; fix by prompting with specific data, angle, and audience</strong> identifies both cause and cure: undirected prompts yield forgettable filler, and specificity restores substance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The reports are too short; make each one much longer</b>: adding length to empty text makes it more forgettable, not less.</span><span class='qd'><b>The font is wrong; change the font for a fresh look</b>: appearance does not address the lack of insight.</span><span class='qd'><b>The AI is broken; stop using AI for reports entirely</b>: the tool is fine; the prompting is the issue.</span>" },
  { id:"D3-004", domain:3, obj:"3.4", diff:"easy", q:"You type 'Tell me about the crash' with no other details, and the AI writes about a stock-market crash when you meant a car crash. What caused this?", options:["A factual hallucination","Outdated training data","A copyright violation","The AI misunderstood the ambiguous context of your request"], answer:3, explain:"<strong>The AI misunderstood the ambiguous context of your request</strong> because 'crash' has many meanings, and without more detail the model guessed the wrong one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A factual hallucination</b>: the AI did not invent false facts; it answered a plausible but unintended interpretation.</span><span class='qd'><b>Outdated training data</b>: the issue is ambiguity in your prompt, not the age of the data.</span><span class='qd'><b>A copyright violation</b>: nothing about copyrighted material is involved in this misread.</span>" },
  { id:"D3-005", domain:3, obj:"3.1", diff:"medium", q:"Which statement BEST describes what a large language model actually 'knows'?", options:["It stores a verified database of facts it looks up on demand","It has no true understanding and instead predicts likely text from patterns","It personally researches every question in real time before answering","It remembers every website exactly and quotes them perfectly"], answer:1, explain:"<strong>It has no true understanding and instead predicts likely text from patterns</strong> captures the core idea: the model produces statistically likely wording, so it can be fluent yet factually wrong.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It stores a verified database of facts it looks up on demand</b>: the model is not a fact database and does not verify claims before producing them.</span><span class='qd'><b>It personally researches every question in real time before answering</b>: a base model does not research live; it draws on patterns from prior training.</span><span class='qd'><b>It remembers every website exactly and quotes them perfectly</b>: the model does not store or reproduce pages verbatim; it generates new text.</span>" },
  { id:"D3-006", domain:3, obj:"3.2", diff:"medium", q:"What does it mean to ask an AI to 'show its work' or 'explain its reasoning'?", options:["To have it list the steps or logic behind its answer so you can judge it","To make it delete the answer and start over","To force it to connect to the live internet","To have it translate the answer into another language"], answer:0, explain:"<strong>To have it list the steps or logic behind its answer so you can judge it</strong> is the purpose: seeing the reasoning helps you spot flawed logic or unsupported leaps before relying on the result.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make it delete the answer and start over</b>: showing work adds explanation; it does not discard the answer.</span><span class='qd'><b>To force it to connect to the live internet</b>: explaining reasoning does not grant internet access; it just reveals the steps.</span><span class='qd'><b>To have it translate the answer into another language</b>: reasoning has nothing to do with translation.</span>" },
  { id:"D3-007", domain:3, obj:"3.3", diff:"easy", q:"An AI writing assistant invents a book title and author that do not exist and presents them as a real citation. What is this type of error commonly called?", options:["A bias error","A hallucination","An outdated-information error","A context error"], answer:1, explain:"<strong>A hallucination</strong> is when an AI fabricates information, such as a fake book, author, or citation, and presents it as real fact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A bias error</b>: bias is skewed or unfair output that favors one group or view, not the invention of a fake source.</span><span class='qd'><b>An outdated-information error</b>: outdated errors come from old training data, but a nonexistent book is fabricated, not merely stale.</span><span class='qd'><b>A context error</b>: a context error means the AI misunderstood your request, whereas here it invented facts.</span>" },
  { id:"D3-008", domain:3, obj:"3.4", diff:"hard", q:"You receive an AI answer that is both surprising (it contradicts your prior understanding) and consequential. According to good verification practice, this combination should make you:", options:["Verify it more rigorously before acting on it","Accept it faster precisely because it is surprising","Ignore your prior understanding entirely","Assume your prior belief is automatically correct"], answer:0, explain:"<strong>Verify it more rigorously before acting on it</strong>: a claim that is both surprising and high-impact carries more risk if wrong, so it deserves stronger scrutiny.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept it faster precisely because it is surprising</b>: novelty is a reason for caution, not haste.</span><span class='qd'><b>Ignore your prior understanding entirely</b>: your prior knowledge is a useful check, not something to discard.</span><span class='qd'><b>Assume your prior belief is automatically correct</b>: your prior could be wrong too, which is why you verify rather than assume.</span>" },
  { id:"D3-009", domain:3, obj:"3.1", diff:"medium", q:"Why might an AI confidently give slightly different answers to the same factual question on different days or in different chats?", options:["It secretly edits reference books overnight","It generates responses probabilistically, so wording and even content can vary","It has a mood that changes from day to day","It only remembers the last user it spoke to"], answer:1, explain:"<strong>It generates responses probabilistically, so wording and even content can vary</strong>: because output is sampled from likely continuations, the same prompt can yield different responses.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It secretly edits reference books overnight</b>: the model does not alter external records; variation comes from generation.</span><span class='qd'><b>It has a mood that changes from day to day</b>: models do not have moods; differences are statistical.</span><span class='qd'><b>It only remembers the last user it spoke to</b>: cross-chat variation is due to probabilistic generation, not memory of one user.</span>" },
  { id:"D3-010", domain:3, obj:"3.2", diff:"easy", q:"'Cross-checking' an AI answer means:", options:["Asking the AI to repeat itself once more","Changing the font of the answer","Confirming the same claim using one or more separate, reliable sources","Deleting the answer and moving on"], answer:2, explain:"<strong>Confirming the same claim using one or more separate, reliable sources</strong> defines cross-checking: you validate the claim against independent references.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asking the AI to repeat itself once more</b>: repetition from the same source is not an independent check.</span><span class='qd'><b>Changing the font of the answer</b>: formatting has no bearing on accuracy.</span><span class='qd'><b>Deleting the answer and moving on</b>: deleting it verifies nothing.</span>" },
  { id:"D3-011", domain:3, obj:"3.3", diff:"medium", q:"An AI recommends a business tactic that was standard several years ago but has since been made non-compliant by a new regulation. This is MOST directly a case of:", options:["Outdated information due to the training cutoff","Bias against a particular group","A privacy leak","Prompt ambiguity"], answer:0, explain:"<strong>Outdated information due to the training cutoff</strong> fits: the model's knowledge ends at its cutoff, so it cannot account for a regulation introduced afterward.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bias against a particular group</b>: the advice is stale, not skewed against a group.</span><span class='qd'><b>A privacy leak</b>: no personal data was exposed.</span><span class='qd'><b>Prompt ambiguity</b>: the question was clear; the gap is the age of the model's knowledge.</span>" },
  { id:"D3-012", domain:3, obj:"3.4", diff:"hard", q:"You are triaging ten AI answers by verification priority. Which should you verify FIRST?", options:["A low-stakes suggestion for a lunch spot","A casual analogy buried in a rough draft","A figure that will be filed in a legally binding regulatory report","A minor synonym choice in a sentence"], answer:2, explain:"<strong>A figure that will be filed in a legally binding regulatory report</strong> should be verified first because it carries the highest stakes and legal consequences if wrong.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A low-stakes suggestion for a lunch spot</b>: a wrong lunch pick has trivial consequences.</span><span class='qd'><b>A casual analogy buried in a rough draft</b>: an imperfect analogy in a draft is low-risk and easily fixed.</span><span class='qd'><b>A minor synonym choice in a sentence</b>: a synonym has negligible impact and low priority.</span>" },
  { id:"D3-013", domain:3, obj:"3.1", diff:"easy", q:"The phrase 'garbage in, garbage out' applied to AI training data means:", options:["AI physically produces garbage output","AI cleans all of its training data automatically","Data quality does not affect the output at all","If the training data contains errors or bias, the AI's outputs can inherit them"], answer:3, explain:"<strong>If the training data contains errors or bias, the AI's outputs can inherit them</strong>: flawed input data leads to flawed or biased outputs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI physically produces garbage output</b>: the phrase is figurative, about data quality.</span><span class='qd'><b>AI cleans all of its training data automatically</b>: models do not automatically fix bad training data.</span><span class='qd'><b>Data quality does not affect the output at all</b>: this is the opposite of the phrase's meaning.</span>" },
  { id:"D3-014", domain:3, obj:"3.2", diff:"medium", q:"You want to verify a surprising statistic an AI gave you. Which request is the STRONGEST verification move?", options:["'Are you sure about that?'","'Provide the specific sources or studies this statistic comes from so I can check them.'","'Make the number a bit bigger.'","'Say it again but shorter.'"], answer:1, explain:"<strong>'Provide the specific sources or studies this statistic comes from so I can check them.'</strong> is strongest because it lets you trace the claim to a real, checkable source rather than relying on the model's confidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>'Are you sure about that?'</b>: asking if it is sure often just yields another confident restatement, not evidence.</span><span class='qd'><b>'Make the number a bit bigger.'</b>: this changes the claim rather than verifying it.</span><span class='qd'><b>'Say it again but shorter.'</b>: rephrasing length does nothing to confirm accuracy.</span>" },
  { id:"D3-015", domain:3, obj:"3.3", diff:"medium", q:"A hiring manager uses an AI tool to screen resumes and notices it consistently ranks candidates from one demographic higher for no job-related reason. This is an example of:", options:["A hallucination","Bias in the AI's output","An outdated-information error","A context misunderstanding"], answer:1, explain:"<strong>Bias in the AI's output</strong> describes systematic unfair favoring of one group for reasons unrelated to the job, reflecting skew learned from training data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A hallucination</b>: no false fact was invented; the problem is unfair ranking.</span><span class='qd'><b>An outdated-information error</b>: the issue is unfairness, not stale data.</span><span class='qd'><b>A context misunderstanding</b>: the AI understood the task but produced skewed results.</span>" },
  { id:"D3-016", domain:3, obj:"3.4", diff:"easy", q:"Before you rely on an AI answer for an important decision, judging how believable it is and what could go wrong if it is incorrect is called assessing its:", options:["Word count","Reading level","Font and formatting","Plausibility and risk"], answer:3, explain:"<strong>Plausibility and risk</strong> is exactly what you weigh: how believable the answer is and how damaging a mistake would be guide how carefully you must verify.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Word count</b>: length says nothing about whether the content is correct or safe to rely on.</span><span class='qd'><b>Reading level</b>: how easy the text is to read does not indicate its accuracy or stakes.</span><span class='qd'><b>Font and formatting</b>: appearance is unrelated to whether the claim is trustworthy.</span>" },
  { id:"D3-017", domain:3, obj:"3.1", diff:"hard", q:"A student argues, 'The AI never says it is unsure, so its answers must be reliable.' What is the strongest counterpoint?", options:["The AI is legally required to be correct","Silence about doubt proves accuracy","Models can only make mistakes when they express doubt","Lack of expressed doubt does not mean the answer is correct; models often sound sure while being wrong"], answer:3, explain:"<strong>Lack of expressed doubt does not mean the answer is correct; models often sound sure while being wrong</strong> is the strongest counterpoint: absence of hedging is not evidence of truth.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI is legally required to be correct</b>: there is no such guarantee, and models routinely err.</span><span class='qd'><b>Silence about doubt proves accuracy</b>: not voicing doubt proves nothing about correctness.</span><span class='qd'><b>Models can only make mistakes when they express doubt</b>: models make mistakes most often precisely when they sound confident.</span>" },
  { id:"D3-018", domain:3, obj:"3.2", diff:"medium", q:"A reporter uses AI to draft an article and then confirms every named fact, date, and quote against primary sources before publishing. This practice is BEST described as:", options:["Responsible verification of AI output","Blind trust in the tool","Ignoring the AI entirely","Fully automating publication"], answer:0, explain:"<strong>Responsible verification of AI output</strong> describes confirming each factual element against primary sources before relying on it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Blind trust in the tool</b>: blind trust is accepting output without checking, the opposite of what happened.</span><span class='qd'><b>Ignoring the AI entirely</b>: the reporter used the AI and then verified, so it was not ignored.</span><span class='qd'><b>Fully automating publication</b>: the reporter added a human verification step, not automation.</span>" },
  { id:"D3-019", domain:3, obj:"3.3", diff:"easy", q:"'Slop' in the context of AI content refers to:", options:["A type of secure encryption","A verified academic citation","Low-quality, generic, mass-produced text that lacks real substance","A hardware failure in the model"], answer:2, explain:"<strong>Low-quality, generic, mass-produced text that lacks real substance</strong> is what 'slop' means: filler content that reads smoothly but conveys little of value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A type of secure encryption</b>: slop is a content-quality term, not a security mechanism.</span><span class='qd'><b>A verified academic citation</b>: slop is the opposite of substantive, sourced writing.</span><span class='qd'><b>A hardware failure in the model</b>: slop describes text quality, not equipment.</span>" },
  { id:"D3-020", domain:3, obj:"3.4", diff:"medium", q:"A verification workflow for an important AI answer should BEGIN with which step?", options:["Immediately publish the answer","Delete the conversation to start clean","Change the AI's settings","Assess how plausible and how high-stakes the answer is"], answer:3, explain:"<strong>Assess how plausible and how high-stakes the answer is</strong> is the right first step: judging plausibility and risk tells you how much verification the answer needs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately publish the answer</b>: publishing before any check defeats the purpose of verification.</span><span class='qd'><b>Delete the conversation to start clean</b>: deleting it prevents any verification at all.</span><span class='qd'><b>Change the AI's settings</b>: adjusting settings is not a verification step for a specific claim.</span>" },
  { id:"D3-021", domain:3, obj:"3.1", diff:"hard", q:"A user notices an AI gives a very specific-sounding statistic ('exactly 73.4% of users') for a niche topic with little public data. What is the MOST prudent assumption?", options:["Suspiciously precise figures on data-poor topics may be fabricated and need verification","The precision proves the statistic is accurate","Any number with a decimal is always correct","The AI must have surveyed those users directly"], answer:0, explain:"<strong>Suspiciously precise figures on data-poor topics may be fabricated and need verification</strong> is prudent: oddly exact numbers where little data exists are a classic hallucination pattern.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The precision proves the statistic is accurate</b>: false precision can be invented; precision is not proof.</span><span class='qd'><b>Any number with a decimal is always correct</b>: a decimal point does not make a figure true.</span><span class='qd'><b>The AI must have surveyed those users directly</b>: the model does not conduct surveys; it generates text.</span>" },
  { id:"D3-022", domain:3, obj:"3.2", diff:"easy", q:"Which is a reliable source to verify a historical date an AI provided?", options:["A random social media post","A comment section under a video","A well-established encyclopedia or academic reference","The same AI, asked the question twice"], answer:2, explain:"<strong>A well-established encyclopedia or academic reference</strong> is a reliable, vetted source suitable for confirming a historical date.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A random social media post</b>: an unverified post is not a trustworthy reference.</span><span class='qd'><b>A comment section under a video</b>: comments are unvetted and often inaccurate.</span><span class='qd'><b>The same AI, asked the question twice</b>: re-asking the same model is not independent verification.</span>" },
  { id:"D3-023", domain:3, obj:"3.3", diff:"medium", q:"An AI text generator produces an essay that is coherent but says nothing a knowledgeable reader would find new or specific. To a subject expert, the essay is:", options:["A guarantee of high quality because it is hallucination-free","Proof the AI is a true expert","Generic filler that lacks depth and specificity","An outdated-information error"], answer:2, explain:"<strong>Generic filler that lacks depth and specificity</strong> is how an expert would judge coherent-but-empty text: readable slop with no real insight.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A guarantee of high quality because it is hallucination-free</b>: being free of fabrication does not make empty text high quality.</span><span class='qd'><b>Proof the AI is a true expert</b>: producing filler is the opposite of demonstrating expertise.</span><span class='qd'><b>An outdated-information error</b>: the essay's flaw is emptiness, not stale facts.</span>" },
  { id:"D3-024", domain:3, obj:"3.4", diff:"medium", q:"An AI answer is fluent and detailed but is being used to guide a medical dosage decision. Given the high stakes, what is the MOST appropriate action?", options:["Rely on it immediately since it is detailed","Verify it with a qualified medical professional or authoritative clinical source before acting","Assume that detail means accuracy","Ask the AI to reassure you it is correct"], answer:1, explain:"<strong>Verify it with a qualified medical professional or authoritative clinical source before acting</strong> is right because the risk of harm is severe, so a high-stakes answer must be confirmed by a trusted human expert or authoritative source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rely on it immediately since it is detailed</b>: detail does not equal correctness, and the danger here is too high to skip verification.</span><span class='qd'><b>Assume that detail means accuracy</b>: fluent detail can accompany a fabricated or wrong answer.</span><span class='qd'><b>Ask the AI to reassure you it is correct</b>: self-reassurance from the model is not independent evidence.</span>" },
  { id:"D3-025", domain:3, obj:"3.1", diff:"easy", q:"Which is the BEST one-line explanation of a hallucination for a beginner?", options:["The AI shows you a picture","The AI refuses to answer a question","The AI translates your text into another language","The AI states something false as if it were true"], answer:3, explain:"<strong>The AI states something false as if it were true</strong> is the clearest beginner definition of a hallucination.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI shows you a picture</b>: displaying an image is unrelated to fabricating a fact.</span><span class='qd'><b>The AI refuses to answer a question</b>: refusing is the opposite of confidently stating a false claim.</span><span class='qd'><b>The AI translates your text into another language</b>: translation is a normal task, not a hallucination.</span>" },
  { id:"D3-026", domain:3, obj:"3.2", diff:"hard", q:"You need to confirm a technical claim an AI made about how a specific software feature works. Which is the MOST reliable verification source?", options:["A random comment on a forum","The official vendor documentation for that software","Asking the same AI to confirm itself","A meme about the software"], answer:1, explain:"<strong>The official vendor documentation for that software</strong> is the most reliable source because it is the authoritative, primary reference maintained by the makers of the product.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A random comment on a forum</b>: an unvetted comment may be wrong, outdated, or opinion.</span><span class='qd'><b>Asking the same AI to confirm itself</b>: self-confirmation is not independent and can repeat the same error.</span><span class='qd'><b>A meme about the software</b>: a meme carries no reliable technical authority.</span>" },
  { id:"D3-027", domain:3, obj:"3.3", diff:"medium", q:"An AI drafts marketing copy that unintentionally reinforces a harmful stereotype about a group. What is the BEST immediate action?", options:["Publish it and monitor for complaints","Revise it to remove the biased framing before it is used","Add a disclaimer and publish anyway","Ask the AI to make the stereotype stronger"], answer:1, explain:"<strong>Revise it to remove the biased framing before it is used</strong> is best: catching and correcting bias before publication prevents harm and reputational damage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish it and monitor for complaints</b>: releasing known-biased content and waiting for complaints causes avoidable harm.</span><span class='qd'><b>Add a disclaimer and publish anyway</b>: a disclaimer does not undo the harmful framing.</span><span class='qd'><b>Ask the AI to make the stereotype stronger</b>: this worsens the exact problem you must fix.</span>" },
  { id:"D3-028", domain:3, obj:"3.4", diff:"easy", q:"A step-by-step verification workflow generally ENDS with which step?", options:["Asking the very first question again","Turning off the computer","Ignoring all sources you found","Deciding whether to trust, revise, or discard the answer based on your findings"], answer:3, explain:"<strong>Deciding whether to trust, revise, or discard the answer based on your findings</strong> is the natural final step: after checking, you make an informed decision about the answer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asking the very first question again</b>: that belongs at the start, not the end.</span><span class='qd'><b>Turning off the computer</b>: this is unrelated to concluding verification.</span><span class='qd'><b>Ignoring all sources you found</b>: ignoring sources contradicts the entire purpose of verification.</span>" },
  { id:"D3-029", domain:3, obj:"3.1", diff:"medium", q:"An AI answer contains a mix of correct facts and one subtle false claim woven in. Why is this especially dangerous?", options:["The false claim is always shown in bold","The surrounding correct facts lend false credibility to the wrong claim","It makes the answer noticeably shorter","It automatically alerts the user to the error"], answer:1, explain:"<strong>The surrounding correct facts lend false credibility to the wrong claim</strong>: accurate context can make a nearby error seem trustworthy, so users must verify each claim, not just the overall tone.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The false claim is always shown in bold</b>: errors are not visually flagged in any way.</span><span class='qd'><b>It makes the answer noticeably shorter</b>: mixing facts does not shorten the text or reduce risk.</span><span class='qd'><b>It automatically alerts the user to the error</b>: the model gives no automatic alert about embedded errors.</span>" },
  { id:"D3-030", domain:3, obj:"3.2", diff:"hard", q:"Which combination of moves gives you the STRONGEST verification of a critical AI claim?", options:["Ask the AI 'are you sure' and then re-read the answer","Look only at the answer's tone","Count the words in the answer","Check an authoritative primary source AND cross-reference an independent second source"], answer:3, explain:"<strong>Check an authoritative primary source AND cross-reference an independent second source</strong> is strongest: combining a primary source with independent corroboration provides robust confirmation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask the AI 'are you sure' and then re-read the answer</b>: both steps rely on the same non-independent source.</span><span class='qd'><b>Look only at the answer's tone</b>: tone reveals nothing about accuracy.</span><span class='qd'><b>Count the words in the answer</b>: word count is irrelevant to verification.</span>" },
  { id:"D3-031", domain:3, obj:"3.3", diff:"easy", q:"Which of the following is an example of an OUTDATED-information error, not a hallucination?", options:["Inventing a completely fake company that never existed","Fabricating a statistic out of thin air","Creating a nonexistent quote","Naming a company's CEO who was correct years ago but has since been replaced"], answer:3, explain:"<strong>Naming a company's CEO who was correct years ago but has since been replaced</strong> is outdated information: the fact was once true but is now stale due to the training cutoff.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Inventing a completely fake company that never existed</b>: this is fabrication (a hallucination), not stale fact.</span><span class='qd'><b>Fabricating a statistic out of thin air</b>: an invented number is a hallucination, not outdated data.</span><span class='qd'><b>Creating a nonexistent quote</b>: a made-up quote is fabrication, not outdated information.</span>" },
  { id:"D3-032", domain:3, obj:"3.4", diff:"medium", q:"Before acting on an AI answer, asking 'What is the worst that happens if this is wrong?' is a way to assess the answer's:", options:["Grammar","Length","Risk and impact","Color"], answer:2, explain:"<strong>Risk and impact</strong>: imagining the consequences of an error directly measures how much is at stake.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Grammar</b>: the question concerns consequences, not sentence correctness.</span><span class='qd'><b>Length</b>: how long the answer is has nothing to do with the harm of being wrong.</span><span class='qd'><b>Color</b>: color is irrelevant to consequence assessment.</span>" },
  { id:"D3-033", domain:3, obj:"3.1", diff:"medium", q:"Which of the following is the BEST reason NOT to treat an AI chatbot as an infallible source of truth?", options:["It always tells you when it is guessing","It can generate fluent text that is factually incorrect without signaling any doubt","It can only ever repeat verified facts","It never makes mistakes on simple questions"], answer:1, explain:"<strong>It can generate fluent text that is factually incorrect without signaling any doubt</strong> is the key reason: polished wording is not evidence of accuracy, so users must verify important claims themselves.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It always tells you when it is guessing</b>: models often present guesses with full confidence and no warning.</span><span class='qd'><b>It can only ever repeat verified facts</b>: models generate new text and are not limited to verified facts.</span><span class='qd'><b>It never makes mistakes on simple questions</b>: models can err even on simple questions, so this is false.</span>" },
  { id:"D3-034", domain:3, obj:"3.2", diff:"easy", q:"Which prompt is MOST likely to reduce vague, generic AI output?", options:["'Write a 150-word LinkedIn post for a B2B software firm targeting HR managers, using a professional tone and one concrete example.'","'Write something about marketing.'","'Give me marketing.'","'Marketing, please.'"], answer:0, explain:"<strong>'Write a 150-word LinkedIn post for a B2B software firm targeting HR managers, using a professional tone and one concrete example.'</strong> is best because being specific about audience, length, tone, and content steers the model away from filler.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>'Write something about marketing.'</b>: this is broad and undirected, inviting generic output.</span><span class='qd'><b>'Give me marketing.'</b>: it gives the model no goal, audience, or constraints.</span><span class='qd'><b>'Marketing, please.'</b>: it is even vaguer and will almost certainly produce cliche-filled text.</span>" },
  { id:"D3-035", domain:3, obj:"3.3", diff:"hard", q:"An organization builds a checklist to catch the six common AI error types before publishing. Which item does NOT belong on that error-type checklist?", options:["Check for fabricated facts (hallucinations)","Check for biased or unfair framing","Check that the response streamed within two seconds","Check for outdated information"], answer:2, explain:"<strong>Check that the response streamed within two seconds</strong> does not belong: response speed is a performance metric, not one of the six content error types to review.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Check for fabricated facts (hallucinations)</b>: hallucinations are a core error type that belongs on the checklist.</span><span class='qd'><b>Check for biased or unfair framing</b>: bias is one of the six error types to catch.</span><span class='qd'><b>Check for outdated information</b>: stale data from the training cutoff is a listed error type.</span>" },
  { id:"D3-036", domain:3, obj:"3.4", diff:"medium", q:"An AI answer looks implausible and clashes with several things you already know to be true. The appropriate response is to:", options:["Treat the implausibility as a warning sign and verify carefully before using it","Accept it because the AI is advanced","Assume your own knowledge must be wrong","Immediately act on it"], answer:0, explain:"<strong>Treat the implausibility as a warning sign and verify carefully before using it</strong>: a clash with known facts is a red flag that should trigger extra checking.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept it because the AI is advanced</b>: sophistication does not make an implausible claim true.</span><span class='qd'><b>Assume your own knowledge must be wrong</b>: your knowledge may well be right; verify rather than assume.</span><span class='qd'><b>Immediately act on it</b>: acting on a red-flagged claim without checking is risky.</span>" },
  { id:"D3-037", domain:3, obj:"3.1", diff:"easy", q:"Which statement about AI 'confidence' is TRUE?", options:["A confident tone reliably indicates a correct answer","A confident tone is a writing style and does not measure factual accuracy","A confident tone means the AI checked a source","Confidence only appears when the AI is right"], answer:1, explain:"<strong>A confident tone is a writing style and does not measure factual accuracy</strong> is true: the assured phrasing is generated text, not a signal of verified correctness.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A confident tone reliably indicates a correct answer</b>: confident wording accompanies both right and wrong answers.</span><span class='qd'><b>A confident tone means the AI checked a source</b>: a confident tone implies no source-checking occurred.</span><span class='qd'><b>Confidence only appears when the AI is right</b>: the model is often confidently wrong, so this is false.</span>" },
  { id:"D3-038", domain:3, obj:"3.2", diff:"medium", q:"You ask an AI for sources and it lists several links. What is the correct NEXT step?", options:["Trust them because the links look official","Actually open and read each link to confirm it exists and supports the claim","Assume the first link is enough without opening it","Ignore the links entirely"], answer:1, explain:"<strong>Actually open and read each link to confirm it exists and supports the claim</strong> is correct because AI can list fake or mismatched links, so you must verify each one really backs the statement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust them because the links look official</b>: an official appearance can be fabricated; only opening them confirms anything.</span><span class='qd'><b>Assume the first link is enough without opening it</b>: an unopened link verifies nothing and may not support the claim.</span><span class='qd'><b>Ignore the links entirely</b>: ignoring provided sources wastes the chance to verify.</span>" },
  { id:"D3-039", domain:3, obj:"3.3", diff:"hard", q:"An AI tool used for loan decisions denies more applications from one neighborhood based on patterns in biased historical data. This is a serious example of:", options:["An outdated-information error","A formatting error","Harmful bias with real-world consequences","A privacy-enhancing feature"], answer:2, explain:"<strong>Harmful bias with real-world consequences</strong>: biased training data can drive discriminatory outcomes that materially affect people's lives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An outdated-information error</b>: the problem is discriminatory skew, not stale facts.</span><span class='qd'><b>A formatting error</b>: this is a fairness issue, not a display problem.</span><span class='qd'><b>A privacy-enhancing feature</b>: it harms people rather than protecting privacy.</span>" },
  { id:"D3-040", domain:3, obj:"3.4", diff:"easy", q:"Which factor makes an AI answer HIGHER risk to rely on without verification?", options:["It is a fun fact for a trivia game","It is a suggestion for a color scheme","It will guide a legal or financial decision with real consequences","It is a casual brainstorming idea"], answer:2, explain:"<strong>It will guide a legal or financial decision with real consequences</strong> raises risk because a mistake could cause real harm, demanding careful verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is a fun fact for a trivia game</b>: a wrong trivia answer carries little consequence.</span><span class='qd'><b>It is a suggestion for a color scheme</b>: an aesthetic choice is low-stakes and easily changed.</span><span class='qd'><b>It is a casual brainstorming idea</b>: brainstorming output is meant to be reviewed, so an error is low-risk.</span>" },
  { id:"D3-041", domain:3, obj:"3.1", diff:"medium", q:"Which analogy BEST captures how a language model produces answers?", options:["Like a very advanced autocomplete that predicts likely words from patterns","Like a librarian who looks up the exact book and reads a verified answer","Like a calculator that always returns the one correct result","Like a search engine that returns ranked live web pages"], answer:0, explain:"<strong>Like a very advanced autocomplete that predicts likely words from patterns</strong> is the best analogy: the model chooses probable continuations rather than retrieving a verified fact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Like a librarian who looks up the exact book and reads a verified answer</b>: the model does not look up or read a specific verified source.</span><span class='qd'><b>Like a calculator that always returns the one correct result</b>: unlike a calculator, the model can return varying, sometimes wrong answers.</span><span class='qd'><b>Like a search engine that returns ranked live web pages</b>: a base model does not fetch live pages; it generates text.</span>" },
  { id:"D3-042", domain:3, obj:"3.2", diff:"medium", q:"You suspect an AI answer is too shallow. Which follow-up BEST tests whether it truly understands the topic?", options:["'Give me the same thing again.'","'What are the exceptions or edge cases where this would NOT be true, and why?'","'Make it bold.'","'Answer yes or no only.'"], answer:1, explain:"<strong>'What are the exceptions or edge cases where this would NOT be true, and why?'</strong> best probes depth by forcing the model to reason about limits and nuance rather than restate a surface claim.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>'Give me the same thing again.'</b>: repetition reveals no additional understanding.</span><span class='qd'><b>'Make it bold.'</b>: styling does not test comprehension.</span><span class='qd'><b>'Answer yes or no only.'</b>: restricting to yes/no removes the reasoning you want to see.</span>" },
  { id:"D3-043", domain:3, obj:"3.3", diff:"easy", q:"Which of the following is an ETHICAL risk of relying on AI output without review?", options:["The answer might be slightly longer than expected","The text might use a serif font","It could reproduce copyrighted material or leak private data","It could load a second faster"], answer:2, explain:"<strong>It could reproduce copyrighted material or leak private data</strong> is a genuine ethical risk tied to intellectual property and privacy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The answer might be slightly longer than expected</b>: length is a style matter, not an ethical risk.</span><span class='qd'><b>The text might use a serif font</b>: font choice raises no ethical concern.</span><span class='qd'><b>It could load a second faster</b>: speed is unrelated to ethics.</span>" },
  { id:"D3-044", domain:3, obj:"3.4", diff:"hard", q:"You must present an AI-generated market figure to executives tomorrow. It is plausible but you cannot find any supporting source. What is the MOST responsible action?", options:["Present it clearly labeled as unverified, or omit it until you can confirm it","Present it as a confirmed fact","Round it up to make it look stronger","Attribute it to a made-up study to add credibility"], answer:0, explain:"<strong>Present it clearly labeled as unverified, or omit it until you can confirm it</strong> is most responsible: without a source, you must not pass an unverified figure off as fact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Present it as a confirmed fact</b>: labeling unverified data as confirmed misleads decision-makers.</span><span class='qd'><b>Round it up to make it look stronger</b>: altering an already-unverified number compounds the problem.</span><span class='qd'><b>Attribute it to a made-up study to add credibility</b>: inventing a source is fabrication and unethical.</span>" },
  { id:"D3-045", domain:3, obj:"3.1", diff:"medium", q:"An AI confidently explains a scientific concept but gets a key detail backwards, and a subject-matter expert catches it instantly. What lesson does this BEST teach?", options:["Domain expertise is a powerful check on AI output","Experts are never needed once you have AI","AI should never explain science","The expert must be mistaken because the AI sounded sure"], answer:0, explain:"<strong>Domain expertise is a powerful check on AI output</strong>: someone who knows the field can spot subtle errors that fluent AI text might hide from a novice.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Experts are never needed once you have AI</b>: this case shows the opposite; the expert caught the mistake.</span><span class='qd'><b>AI should never explain science</b>: AI can explain science usefully, provided its output is verified.</span><span class='qd'><b>The expert must be mistaken because the AI sounded sure</b>: confident tone is not evidence, and the expert was right.</span>" },
  { id:"D3-046", domain:3, obj:"3.2", diff:"easy", q:"Being 'specific' in a prompt helps verification because:", options:["Longer prompts always produce true answers","It hides the AI's mistakes from view","A precise, well-scoped answer is easier to check against reliable sources","Specific prompts disable hallucinations entirely"], answer:2, explain:"<strong>A precise, well-scoped answer is easier to check against reliable sources</strong>: specificity yields a narrower claim you can verify point by point.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Longer prompts always produce true answers</b>: length alone does not guarantee truth.</span><span class='qd'><b>It hides the AI's mistakes from view</b>: specificity surfaces mistakes for checking, it does not hide them.</span><span class='qd'><b>Specific prompts disable hallucinations entirely</b>: good prompts reduce, but cannot fully eliminate, hallucinations.</span>" },
  { id:"D3-047", domain:3, obj:"3.3", diff:"medium", q:"A user pastes confidential customer records into a public AI chatbot to get a summary. Which risk category does this BEST illustrate?", options:["Availability risk","Outdated-information risk","Formatting risk","Privacy and data-handling risk"], answer:3, explain:"<strong>Privacy and data-handling risk</strong> is illustrated: putting confidential personal data into a public tool can expose it and breach privacy obligations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Availability risk</b>: availability concerns uptime, not exposure of sensitive data.</span><span class='qd'><b>Outdated-information risk</b>: staleness of data is unrelated to leaking confidential records.</span><span class='qd'><b>Formatting risk</b>: how text is formatted is irrelevant to a privacy exposure.</span>" },
  { id:"D3-048", domain:3, obj:"3.4", diff:"hard", q:"An AI answer seems plausible, is low-stakes, and is trivially easy to confirm with a quick glance at a reliable site. What is the PROPORTIONATE verification response?", options:["Launch a full multi-source investigation","Do a quick single check and move on","Never verify low-stakes items at all","Escalate it to senior management"], answer:1, explain:"<strong>Do a quick single check and move on</strong> is proportionate: low stakes plus easy confirmation warrant a light verification touch rather than heavy effort.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Launch a full multi-source investigation</b>: exhaustive verification is overkill for a trivial, low-risk item.</span><span class='qd'><b>Never verify low-stakes items at all</b>: a quick check is still cheap and worthwhile when it takes seconds.</span><span class='qd'><b>Escalate it to senior management</b>: escalating a trivial fact wastes others' time.</span>" },
  { id:"D3-049", domain:3, obj:"3.1", diff:"easy", q:"Which is TRUE about AI and the sources it lists?", options:["An AI always uses exactly the sources it lists","An AI never provides sources","Listed sources are guaranteed to be real","An AI can list sources it did not actually use and may fabricate citations"], answer:3, explain:"<strong>An AI can list sources it did not actually use and may fabricate citations</strong>: models can produce plausible-looking references that are wrong or invented, so listed sources must be verified.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An AI always uses exactly the sources it lists</b>: the listed sources may not correspond to anything real.</span><span class='qd'><b>An AI never provides sources</b>: models often do provide sources, though not always accurate ones.</span><span class='qd'><b>Listed sources are guaranteed to be real</b>: there is no such guarantee; some are fabricated.</span>" },
  { id:"D3-050", domain:3, obj:"3.2", diff:"medium", q:"You get one answer from an AI and a conflicting answer from a well-known reliable website on the same factual question. What is the BEST interpretation?", options:["The AI is always right, so ignore the website","A conflict is a red flag that at least one source is wrong, so investigate further","The website is always right, so the AI is useless","Both must be correct at the same time"], answer:1, explain:"<strong>A conflict is a red flag that at least one source is wrong, so investigate further</strong> is best because disagreement between sources signals you should dig deeper rather than assume either is authoritative.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI is always right, so ignore the website</b>: AI is not automatically correct, so dismissing the website is unjustified.</span><span class='qd'><b>The website is always right, so the AI is useless</b>: websites can also be wrong or outdated; blanket trust is unwise.</span><span class='qd'><b>Both must be correct at the same time</b>: two directly conflicting answers cannot both be true.</span>" },
  { id:"D3-051", domain:3, obj:"3.3", diff:"medium", q:"An AI model was trained on data ending in a past year. You ask who currently holds a certain elected office and it names someone who left that role after the cutoff. This error is caused by:", options:["The training data cut-off / outdated information","Bias in the training data","A privacy violation","Ambiguous phrasing in your question"], answer:0, explain:"<strong>The training data cut-off / outdated information</strong> is the cause: the model only knows events up to its training cutoff and cannot know changes that happened afterward.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bias in the training data</b>: this is a timing gap, not skewed or unfair treatment of a group.</span><span class='qd'><b>A privacy violation</b>: no personal data was improperly exposed.</span><span class='qd'><b>Ambiguous phrasing in your question</b>: the question was clear; the model simply lacked recent data.</span>" },
  { id:"D3-052", domain:3, obj:"3.4", diff:"easy", q:"When judging the 'plausibility' of an AI answer, a useful question to ask yourself is:", options:["'How many words is it?'","'Did it answer quickly?'","'Does this align with what I or trusted sources already know, and does anything feel off?'","'Is the text a nice color?'"], answer:2, explain:"<strong>'Does this align with what I or trusted sources already know, and does anything feel off?'</strong> is the useful check: comparing the claim to known reliable information helps flag likely errors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>'How many words is it?'</b>: length does not indicate truthfulness.</span><span class='qd'><b>'Did it answer quickly?'</b>: response speed says nothing about accuracy.</span><span class='qd'><b>'Is the text a nice color?'</b>: color is irrelevant to plausibility.</span>" },
  { id:"D3-053", domain:3, obj:"3.1", diff:"hard", q:"Two users ask an AI the same obscure factual question and receive two different confident answers. What does this MOST strongly suggest?", options:["The model may be guessing and generating plausible text rather than recalling a fact","Both answers are equally reliable","The model is broken and should never be used","The users phrased it identically, so the answers must match"], answer:0, explain:"<strong>The model may be guessing and generating plausible text rather than recalling a fact</strong> is the strongest read: inconsistent confident answers indicate the model is producing likely-sounding output, not retrieving a verified fact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Both answers are equally reliable</b>: two conflicting answers cannot both be equally trustworthy.</span><span class='qd'><b>The model is broken and should never be used</b>: this is normal probabilistic behavior, not a defect that bars all use.</span><span class='qd'><b>The users phrased it identically, so the answers must match</b>: identical phrasing does not force identical output from a probabilistic model.</span>" },
  { id:"D3-054", domain:3, obj:"3.2", diff:"medium", q:"Which is the LEAST reliable way to verify an AI's factual claim?", options:["Checking an authoritative primary source","Cross-referencing several reputable independent sources","Consulting a qualified subject-matter expert","Asking the same AI 'Are you sure?' and accepting its yes"], answer:3, explain:"<strong>Asking the same AI 'Are you sure?' and accepting its yes</strong> is least reliable because it is not independent and the model may simply reaffirm its own error.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Checking an authoritative primary source</b>: a primary source is one of the strongest verification methods.</span><span class='qd'><b>Cross-referencing several reputable independent sources</b>: agreement across independent sources is highly reliable.</span><span class='qd'><b>Consulting a qualified subject-matter expert</b>: an expert provides trustworthy independent confirmation.</span>" },
  { id:"D3-055", domain:3, obj:"3.3", diff:"easy", q:"An AI-generated blog intro reads: 'In today's fast-paced world, businesses must leverage synergy to unlock their full potential.' What weakness does this MOST illustrate?", options:["A factual hallucination","A privacy violation","An outdated-information error","Generic, filler 'slop' content with no real substance"], answer:3, explain:"<strong>Generic, filler 'slop' content with no real substance</strong> describes vague, cliche-filled text that says nothing specific, a common weakness of unedited AI output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A factual hallucination</b>: nothing false was invented here; the text is empty, not wrong.</span><span class='qd'><b>A privacy violation</b>: no personal or sensitive data is exposed in the sentence.</span><span class='qd'><b>An outdated-information error</b>: the passage contains no time-sensitive fact that could be stale; it is simply generic.</span>" },
  { id:"D3-056", domain:3, obj:"3.4", diff:"medium", q:"A verification workflow includes: (1) judge stakes, (2) check plausibility, (3) find independent sources, (4) reconcile conflicts, (5) decide. If sources conflict at step 4, the BEST action is to:", options:["Pick whichever source you like best","Average the two answers together automatically","Investigate why they differ and favor the more authoritative, current source","Discard the whole task"], answer:2, explain:"<strong>Investigate why they differ and favor the more authoritative, current source</strong> is best: understanding the conflict and weighting credibility resolves it responsibly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pick whichever source you like best</b>: preference is not a valid basis for accuracy.</span><span class='qd'><b>Average the two answers together automatically</b>: averaging conflicting facts can produce a meaningless middle that is also wrong.</span><span class='qd'><b>Discard the whole task</b>: a conflict is a reason to investigate, not to abandon the work.</span>" },
  { id:"D3-057", domain:3, obj:"3.1", diff:"hard", q:"Which best explains why 'the AI agreed with me when I pushed back, so my correction must be right' is flawed reasoning?", options:["The AI is legally forbidden from agreeing with users","Agreement proves the user is always right","The AI cannot change its answer once given","Models often agree with user corrections to be agreeable, regardless of whether the correction is true"], answer:3, explain:"<strong>Models often agree with user corrections to be agreeable, regardless of whether the correction is true</strong>: this tendency (sycophancy) means agreement is not proof your correction was accurate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The AI is legally forbidden from agreeing with users</b>: there is no such rule; models can and do agree.</span><span class='qd'><b>Agreement proves the user is always right</b>: agreement can occur even when the user is wrong.</span><span class='qd'><b>The AI cannot change its answer once given</b>: models readily change answers, which is part of the problem here.</span>" },
  { id:"D3-058", domain:3, obj:"3.2", diff:"easy", q:"Which is the BEST habit to build for everyday AI use?", options:["Verify important claims and stay skeptical of confident but unsourced output","Believe everything the AI says to save time","Never read the answer at all","Only trust answers written in bold"], answer:0, explain:"<strong>Verify important claims and stay skeptical of confident but unsourced output</strong> is the best habit because it protects against acting on fabricated or biased content.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Believe everything the AI says to save time</b>: uncritical belief invites acting on errors.</span><span class='qd'><b>Never read the answer at all</b>: not reading it defeats the purpose of asking.</span><span class='qd'><b>Only trust answers written in bold</b>: formatting is unrelated to trustworthiness.</span>" },
  { id:"D3-059", domain:3, obj:"3.3", diff:"medium", q:"An AI trained mostly on data from one profession keeps assuming every user is an expert in that field, using heavy jargon. For a general audience, this reflects:", options:["A privacy breach","A perfectly neutral response","Bias toward the overrepresented group in its training data","A hardware limitation"], answer:2, explain:"<strong>Bias toward the overrepresented group in its training data</strong>: skew in the data leads the model to assume a narrow audience and default to that group's jargon.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A privacy breach</b>: no personal data was exposed.</span><span class='qd'><b>A perfectly neutral response</b>: assuming everyone is a specialist is not neutral.</span><span class='qd'><b>A hardware limitation</b>: the issue stems from data composition, not equipment.</span>" },
  { id:"D3-060", domain:3, obj:"3.4", diff:"medium", q:"A user gives the AI a detailed, specific prompt with context, constraints, and examples. Compared with a one-word prompt, this MOST reduces the chance of:", options:["The AI misunderstanding the request and answering the wrong thing","The screen freezing","The keyboard breaking","The internet slowing down"], answer:0, explain:"<strong>The AI misunderstanding the request and answering the wrong thing</strong> is reduced because clear context and constraints leave far less room for the model to misinterpret intent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The screen freezing</b>: prompt detail has no effect on hardware performance.</span><span class='qd'><b>The keyboard breaking</b>: this is unrelated to prompt quality.</span><span class='qd'><b>The internet slowing down</b>: network speed is not affected by how you phrase a prompt.</span>" },
  { id:"D3-061", domain:3, obj:"3.1", diff:"easy", q:"When people say an AI 'doesn't know facts, it predicts text,' what practical caution should a user take from this?", options:["Never use AI for anything at all","Independently verify any important factual claim it makes","Assume every answer is a deliberate lie","Only ask it yes-or-no questions"], answer:1, explain:"<strong>Independently verify any important factual claim it makes</strong> is the practical takeaway: because output is predicted rather than known, users confirm important claims elsewhere.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Never use AI for anything at all</b>: AI remains useful when its output is verified; total avoidance is an overreaction.</span><span class='qd'><b>Assume every answer is a deliberate lie</b>: many answers are correct, so blanket distrust is inaccurate and unhelpful.</span><span class='qd'><b>Only ask it yes-or-no questions</b>: limiting question format does nothing to address factual reliability.</span>" },
  { id:"D3-062", domain:3, obj:"3.2", diff:"hard", q:"An AI gives a step-by-step process you plan to run on a live system. The SAFEST way to verify it first is to:", options:["Follow all steps immediately on the production system","Confirm the steps against official documentation and, if possible, test on a safe copy first","Assume the steps are fine because they are numbered","Skip the risky-looking steps and hope for the best"], answer:1, explain:"<strong>Confirm the steps against official documentation and, if possible, test on a safe copy first</strong> is safest: verifying against authoritative guidance and testing non-destructively catches bad steps before harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Follow all steps immediately on the production system</b>: acting on unverified steps in production risks real damage.</span><span class='qd'><b>Assume the steps are fine because they are numbered</b>: numbering does not make steps correct or safe.</span><span class='qd'><b>Skip the risky-looking steps and hope for the best</b>: guessing which steps to skip can break the process.</span>" },
  { id:"D3-063", domain:3, obj:"3.3", diff:"medium", q:"An AI summarizes a news topic but omits an important development because that event happened after its training cutoff. To get current information, the user should:", options:["Ask the AI to try harder","Consult an up-to-date, reliable source such as a current news outlet or a tool with live data access","Assume nothing has changed since the cutoff","Rephrase the question in all capital letters"], answer:1, explain:"<strong>Consult an up-to-date, reliable source such as a current news outlet or a tool with live data access</strong> is correct because the model cannot know post-cutoff events, so recent facts must come from a current source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ask the AI to try harder</b>: effort cannot conjure information the model never had.</span><span class='qd'><b>Assume nothing has changed since the cutoff</b>: assuming stability can miss critical updates.</span><span class='qd'><b>Rephrase the question in all capital letters</b>: capitalization does not add missing recent data.</span>" },
  { id:"D3-064", domain:3, obj:"3.4", diff:"easy", q:"Which scenario represents the LOWEST-risk use of an unverified AI answer?", options:["Setting a legal contract clause","Deciding a medication dose","Choosing a fun name for a personal playlist","Filing an official tax figure"], answer:2, explain:"<strong>Choosing a fun name for a personal playlist</strong> is lowest risk: a mistake has no meaningful consequence and is easily changed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Setting a legal contract clause</b>: legal wording errors can have serious binding consequences.</span><span class='qd'><b>Deciding a medication dose</b>: a dosing error can cause direct physical harm.</span><span class='qd'><b>Filing an official tax figure</b>: incorrect tax figures can carry legal and financial penalties.</span>" },
  { id:"D3-065", domain:3, obj:"3.1", diff:"medium", q:"An AI states a false fact so smoothly that it is hard to tell it is wrong. What core characteristic of language models does this reveal?", options:["Fluency and correctness are independent — sounding right is not being right","Language models cannot form grammatical sentences","Language models only speak in questions","Fluency guarantees factual accuracy"], answer:0, explain:"<strong>Fluency and correctness are independent — sounding right is not being right</strong> is the key insight: models optimize for natural-sounding text, so polish is no guarantee of truth.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Language models cannot form grammatical sentences</b>: they are highly fluent, which is precisely what makes errors deceptive.</span><span class='qd'><b>Language models only speak in questions</b>: they produce statements, not only questions.</span><span class='qd'><b>Fluency guarantees factual accuracy</b>: this is the opposite of the lesson; fluency guarantees nothing about facts.</span>" },
  { id:"D3-066", domain:3, obj:"3.2", diff:"hard", q:"You have an AI answer and three independent, reputable sources that all agree with it. Compared with relying on the AI alone, this cross-check MOST improves your:", options:["Confidence that the claim is accurate","Word count","Typing speed","Screen brightness"], answer:0, explain:"<strong>Confidence that the claim is accurate</strong> increases because agreement across multiple independent, credible sources is strong evidence the claim is correct.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Word count</b>: cross-checking does not change how long your text is.</span><span class='qd'><b>Typing speed</b>: verification has nothing to do with how fast you type.</span><span class='qd'><b>Screen brightness</b>: this is unrelated to source agreement.</span>" },
  { id:"D3-067", domain:3, obj:"3.3", diff:"easy", q:"An AI reproduces several paragraphs that closely match a copyrighted article without attribution, and a user pastes them into a published document. Which risk is MOST relevant?", options:["Availability risk","Latency risk","Battery-drain risk","Copyright / intellectual-property risk"], answer:3, explain:"<strong>Copyright / intellectual-property risk</strong> is most relevant: using closely-copied protected text without permission or attribution can infringe copyright.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Availability risk</b>: availability concerns uptime, not reuse of protected content.</span><span class='qd'><b>Latency risk</b>: latency is about response speed, unrelated to copyright.</span><span class='qd'><b>Battery-drain risk</b>: power use has nothing to do with intellectual property.</span>" },
  { id:"D3-068", domain:3, obj:"3.4", diff:"medium", q:"You build a rule of thumb: 'The higher the stakes, the more independent verification I require.' An AI suggests a minor wording tweak to an internal email. Applying your rule, you should:", options:["Do a quick sanity check and send it","Demand three expert reviews before sending","Never send any AI-suggested wording","Escalate it to the legal department"], answer:0, explain:"<strong>Do a quick sanity check and send it</strong> correctly applies the rule: a minor internal wording tweak is low-stakes, so light verification is appropriate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Demand three expert reviews before sending</b>: heavy review is disproportionate for a trivial change.</span><span class='qd'><b>Never send any AI-suggested wording</b>: refusing all AI suggestions ignores the low risk here.</span><span class='qd'><b>Escalate it to the legal department</b>: involving legal for a minor internal email wastes resources.</span>" },
  { id:"D3-069", domain:3, obj:"3.1", diff:"medium", q:"Which best explains why an AI might invent a quote and attribute it to a real famous person?", options:["It generates text that fits the pattern of a plausible quote, without checking if it was ever said","It has a recording of everything the person ever said","It always contacts the person first to confirm","It only quotes verified transcripts"], answer:0, explain:"<strong>It generates text that fits the pattern of a plausible quote, without checking if it was ever said</strong>: the model produces something that sounds right for that figure, which can be entirely fabricated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It has a recording of everything the person ever said</b>: the model has no such recording and does not retrieve verified audio.</span><span class='qd'><b>It always contacts the person first to confirm</b>: the model cannot contact anyone; it generates text.</span><span class='qd'><b>It only quotes verified transcripts</b>: it is not limited to verified transcripts and can invent quotes.</span>" },
  { id:"D3-070", domain:3, obj:"3.2", diff:"easy", q:"You want to 'probe the depth' of an AI's answer. Which follow-up BEST does this?", options:["'Explain the underlying reason and give a concrete example.'","'lol ok, thanks'","'Change the color of the text.'","'Repeat exactly what you said.'"], answer:0, explain:"<strong>'Explain the underlying reason and give a concrete example.'</strong> probes depth by pushing the model past a surface claim to reveal reasoning and specifics you can evaluate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>'lol ok, thanks'</b>: this adds nothing and requests no deeper detail.</span><span class='qd'><b>'Change the color of the text.'</b>: formatting requests do not test the substance of the answer.</span><span class='qd'><b>'Repeat exactly what you said.'</b>: repetition surfaces no new reasoning to evaluate.</span>" },
  { id:"D3-071", domain:3, obj:"3.3", diff:"hard", q:"An AI drafts a company FAQ that sounds polished but, on review, every answer is vague, avoids specifics, and could describe any company. A teammate wants to ship it to save time. What is the BEST response?", options:["Ship it; a polished tone is enough for an FAQ","Add more buzzwords to make it sound authoritative","Shorten each answer so the vagueness is less visible","Reject it and re-prompt with the company's actual policies, product details, and real customer questions"], answer:3, explain:"<strong>Reject it and re-prompt with the company's actual policies, product details, and real customer questions</strong> is best: generic 'slop' provides no real value to customers and is fixed by grounding the prompt in concrete facts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ship it; a polished tone is enough for an FAQ</b>: an FAQ that answers nothing specific fails its purpose regardless of tone.</span><span class='qd'><b>Add more buzzwords to make it sound authoritative</b>: buzzwords increase emptiness rather than usefulness.</span><span class='qd'><b>Shorten each answer so the vagueness is less visible</b>: hiding vagueness does not add the missing substance.</span>" },
  { id:"D3-072", domain:3, obj:"3.4", diff:"medium", q:"Which of these situations MOST justifies skipping heavy verification of an AI answer?", options:["The answer determines a medical treatment","The answer sets a company's official financial figures","The answer is a brainstorm of casual birthday-party theme ideas","The answer will be published as journalism"], answer:2, explain:"<strong>The answer is a brainstorm of casual birthday-party theme ideas</strong> justifies light verification because the stakes are minimal and any 'error' is inconsequential.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The answer determines a medical treatment</b>: medical decisions are high-stakes and demand rigorous verification.</span><span class='qd'><b>The answer sets a company's official financial figures</b>: official financials require careful checking.</span><span class='qd'><b>The answer will be published as journalism</b>: published journalism must be fact-checked.</span>" },
  { id:"D3-073", domain:3, obj:"3.1", diff:"easy", q:"A colleague says 'The AI gave me three journal references, so the claim must be legitimate.' What is the flaw in this reasoning?", options:["AI can never produce references at all","References always guarantee a claim is true","Three references are simply too few to matter","AI can fabricate realistic-looking references that do not actually exist"], answer:3, explain:"<strong>AI can fabricate realistic-looking references that do not actually exist</strong> is the flaw: models routinely invent plausible citations, so their presence is not proof, and each reference must be checked.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI can never produce references at all</b>: models can and do produce references, real or fabricated.</span><span class='qd'><b>References always guarantee a claim is true</b>: even genuine references can be misused or misread, so they do not guarantee truth.</span><span class='qd'><b>Three references are simply too few to matter</b>: the count is irrelevant; the concern is whether any of them are real.</span>" },
  { id:"D3-074", domain:3, obj:"3.2", diff:"medium", q:"Asking an AI to 'list the assumptions behind this answer' primarily helps you:", options:["Speed up your internet connection","Reduce the file size of the chat","Change the language of the answer","See hidden premises that, if wrong, would make the answer wrong"], answer:3, explain:"<strong>See hidden premises that, if wrong, would make the answer wrong</strong>: surfacing assumptions lets you test the foundations of the claim before trusting it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Speed up your internet connection</b>: listing assumptions has no effect on network speed.</span><span class='qd'><b>Reduce the file size of the chat</b>: this is unrelated to file size.</span><span class='qd'><b>Change the language of the answer</b>: assumptions are about logic, not translation.</span>" },
  { id:"D3-075", domain:3, obj:"3.3", diff:"hard", q:"An AI writing tool is used to generate hundreds of near-identical product reviews. Beyond raw quality, which additional concern is MOST relevant?", options:["The reviews might load slowly","Ethical concerns about deceptive or inauthentic content misleading readers","The reviews use too many headings","The font is inconsistent between reviews"], answer:1, explain:"<strong>Ethical concerns about deceptive or inauthentic content misleading readers</strong> is most relevant: mass-producing fake-looking reviews can deceive consumers and raise integrity issues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The reviews might load slowly</b>: load speed is a technical issue, not the core concern.</span><span class='qd'><b>The reviews use too many headings</b>: heading count is a minor style matter.</span><span class='qd'><b>The font is inconsistent between reviews</b>: font consistency is trivial next to the ethics of deception.</span>" },
  { id:"D3-076", domain:3, obj:"3.4", diff:"easy", q:"A manager wants a simple policy for when staff must verify AI output. The MOST defensible principle is:", options:["Match verification effort to the stakes and the ease of confirming the claim","Verify nothing so the team can move fast","Verify everything with three experts regardless of stakes","Only verify answers that are longer than one page"], answer:0, explain:"<strong>Match verification effort to the stakes and the ease of confirming the claim</strong> is most defensible: it concentrates scrutiny where errors matter most while staying efficient.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Verify nothing so the team can move fast</b>: skipping all verification invites costly mistakes.</span><span class='qd'><b>Verify everything with three experts regardless of stakes</b>: uniform heavy review wastes resources on trivial items.</span><span class='qd'><b>Only verify answers that are longer than one page</b>: length is unrelated to whether a claim is high-stakes.</span>" },
  { id:"D3-077", domain:3, obj:"3.1", diff:"medium", q:"A model with a training cutoff cannot, on its own, know about an event that happened yesterday. This is because:", options:["Its knowledge was fixed at training time and it has no inherent live awareness","It refuses to learn anything new","It deletes recent events on purpose","It only knows about future events"], answer:0, explain:"<strong>Its knowledge was fixed at training time and it has no inherent live awareness</strong>: without a live data tool, the model's knowledge stops at its cutoff.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It refuses to learn anything new</b>: it is not refusing; it simply was not trained on newer data.</span><span class='qd'><b>It deletes recent events on purpose</b>: there is nothing to delete; it never had the recent data.</span><span class='qd'><b>It only knows about future events</b>: it cannot know the future; it knows up to its cutoff.</span>" },
  { id:"D3-078", domain:3, obj:"3.2", diff:"medium", q:"Which follow-up prompt is the BEST way to make an AI 'show its work' on a math or logic answer?", options:["'Just give me the final number.'","'Walk me through each calculation step so I can check them.'","'Make the answer look prettier.'","'Answer in exactly one word.'"], answer:1, explain:"<strong>'Walk me through each calculation step so I can check them.'</strong> makes the model expose its reasoning so you can catch any faulty step.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>'Just give me the final number.'</b>: hiding the steps prevents you from checking the logic.</span><span class='qd'><b>'Make the answer look prettier.'</b>: appearance does not reveal reasoning.</span><span class='qd'><b>'Answer in exactly one word.'</b>: a single word gives you nothing to verify.</span>" },
  { id:"D3-079", domain:3, obj:"3.3", diff:"easy", q:"An AI-written product description repeats the same three adjectives, avoids any specific feature, and could apply to almost any product. What should you do to improve it?", options:["Publish it as is because AI text is naturally optimized","Prompt again with specific product features, target buyer, and unique selling points","Add more of the same adjectives","Translate it to sound more professional"], answer:1, explain:"<strong>Prompt again with specific product features, target buyer, and unique selling points</strong> is correct because generic 'slop' is fixed by feeding the model concrete details so its output becomes distinctive.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish it as is because AI text is naturally optimized</b>: unedited generic copy is weak, not optimized.</span><span class='qd'><b>Add more of the same adjectives</b>: piling on adjectives deepens the vagueness rather than adding substance.</span><span class='qd'><b>Translate it to sound more professional</b>: translation does not add the missing specifics.</span>" },
  { id:"D3-080", domain:3, obj:"3.4", diff:"hard", q:"A workflow says: for any answer you plan to rely on, (a) rate its stakes, (b) rate how confident you are, then (c) verify proportionally. An answer is high-stakes but you feel very confident it is right. You should:", options:["Still verify, because high stakes justify checking even a confident-feeling answer","Skip verification because you feel confident","Mentally lower the stakes so you can skip checking","Rely on your feeling alone"], answer:0, explain:"<strong>Still verify, because high stakes justify checking even a confident-feeling answer</strong>: feelings of confidence are not proof, and high consequences warrant verification regardless.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Skip verification because you feel confident</b>: subjective confidence can be misplaced, and the stakes are high.</span><span class='qd'><b>Mentally lower the stakes so you can skip checking</b>: wishful reframing does not reduce the real-world consequences.</span><span class='qd'><b>Rely on your feeling alone</b>: a feeling is not independent evidence for a high-stakes decision.</span>" },
  { id:"D3-081", domain:3, obj:"3.1", diff:"medium", q:"Why is it risky to use AI output as your ONLY source for a decision that affects other people?", options:["AI answers are always too short to be useful","AI cannot produce full sentences","AI can be confidently wrong or biased, and errors could harm those people","AI only works on weekends"], answer:2, explain:"<strong>AI can be confidently wrong or biased, and errors could harm those people</strong>: relying solely on unverified AI for decisions affecting others risks passing errors and bias onto them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI answers are always too short to be useful</b>: length is not the issue and answers are often lengthy.</span><span class='qd'><b>AI cannot produce full sentences</b>: AI produces fluent, complete sentences.</span><span class='qd'><b>AI only works on weekends</b>: availability is not the concern; reliability is.</span>" },
  { id:"D3-082", domain:3, obj:"3.2", diff:"easy", q:"Which action provides the STRONGEST independent evidence that an AI's claim is accurate?", options:["Re-reading the AI answer twice","Noticing that the answer is well formatted","Seeing that the answer is long","Finding the claim confirmed in an authoritative primary source"], answer:3, explain:"<strong>Finding the claim confirmed in an authoritative primary source</strong> gives the strongest independent evidence because it validates the claim outside the model.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Re-reading the AI answer twice</b>: rereading the same output adds no new evidence.</span><span class='qd'><b>Noticing that the answer is well formatted</b>: formatting does not confirm accuracy.</span><span class='qd'><b>Seeing that the answer is long</b>: length is not evidence of correctness.</span>" },
  { id:"D3-083", domain:3, obj:"3.3", diff:"medium", q:"An employee asks a public AI to draft a memo and pastes in unreleased financial results. The PRIMARY problem is:", options:["The memo might be too formal","The memo could be too short","Sensitive confidential data may be exposed outside the company","The AI writes too quickly"], answer:2, explain:"<strong>Sensitive confidential data may be exposed outside the company</strong>: submitting unreleased financials to a public tool risks a serious data leak.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The memo might be too formal</b>: tone is trivial next to a data-exposure risk.</span><span class='qd'><b>The memo could be too short</b>: length is irrelevant to the confidentiality breach.</span><span class='qd'><b>The AI writes too quickly</b>: speed is not the concern here.</span>" },
  { id:"D3-084", domain:3, obj:"3.4", diff:"hard", q:"Which combination of factors should MOST increase the verification effort you apply to an AI answer?", options:["High stakes and an answer that is hard to independently confirm","Low stakes and an answer you can easily confirm","A short answer with a friendly tone","An answer that agrees with what you already believe"], answer:0, explain:"<strong>High stakes and an answer that is hard to independently confirm</strong> should raise your effort the most because both the cost of being wrong and the uncertainty are high.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Low stakes and an answer you can easily confirm</b>: low risk plus easy checking calls for less effort, not more.</span><span class='qd'><b>A short answer with a friendly tone</b>: length and tone are irrelevant to how much verification is needed.</span><span class='qd'><b>An answer that agrees with what you already believe</b>: agreement can lull you into skipping checks, so it should not drive effort down on its own.</span>" },
  { id:"D3-085", domain:3, obj:"3.1", diff:"easy", q:"Which practice BEST reflects a healthy verification mindset when using AI for research?", options:["Accept the first answer to save time","Treat AI output as a starting point to be confirmed, not a final source of truth","Only verify answers that seem boring","Trust AI more than any human expert"], answer:1, explain:"<strong>Treat AI output as a starting point to be confirmed, not a final source of truth</strong> reflects the correct mindset: AI can accelerate research, but claims should be validated against reliable sources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept the first answer to save time</b>: skipping verification invites acting on errors.</span><span class='qd'><b>Only verify answers that seem boring</b>: importance and risk, not how interesting an answer is, should drive verification.</span><span class='qd'><b>Trust AI more than any human expert</b>: blindly ranking AI above experts ignores AI's known failure modes.</span>" },
  { id:"D3-086", domain:3, obj:"3.2", diff:"medium", q:"An AI gives a plausible answer, but you cannot find any independent source that confirms OR denies it. The MOST responsible stance is to:", options:["Treat it as confirmed fact","Treat it as unverified and avoid relying on it for anything important","Assume it is definitely false","Publish it as breaking news"], answer:1, explain:"<strong>Treat it as unverified and avoid relying on it for anything important</strong>: without corroboration, the claim is neither confirmed nor safe to depend on for high-stakes use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Treat it as confirmed fact</b>: nothing confirmed it, so calling it fact is unjustified.</span><span class='qd'><b>Assume it is definitely false</b>: lack of confirmation does not prove it false either.</span><span class='qd'><b>Publish it as breaking news</b>: publishing unverified claims is irresponsible.</span>" },
  { id:"D3-087", domain:3, obj:"3.3", diff:"medium", q:"Which is the BEST way to reduce bias in AI-generated content you plan to publish?", options:["Publish quickly before anyone notices","Add more adjectives to the text","Review the output for skewed assumptions and revise, ideally with diverse human perspectives","Trust the AI to self-correct without any review"], answer:2, explain:"<strong>Review the output for skewed assumptions and revise, ideally with diverse human perspectives</strong> is best because human review from varied viewpoints catches and corrects bias the model may reproduce.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Publish quickly before anyone notices</b>: rushing to publish biased content causes harm.</span><span class='qd'><b>Add more adjectives to the text</b>: adjectives do not address underlying bias.</span><span class='qd'><b>Trust the AI to self-correct without any review</b>: the model may not recognize its own bias, so human review is needed.</span>" },
  { id:"D3-088", domain:3, obj:"3.4", diff:"easy", q:"A verification workflow for an important AI answer is BEST summarized as which sequence?", options:["Accept, publish, forget about it","Repeat the question until you like the answer","Assess stakes, check plausibility, find independent sources, reconcile conflicts, then decide","Trust the most confident-sounding response"], answer:2, explain:"<strong>Assess stakes, check plausibility, find independent sources, reconcile conflicts, then decide</strong> captures a sound, repeatable verification process from risk judgment to final decision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accept, publish, forget about it</b>: this skips all verification.</span><span class='qd'><b>Repeat the question until you like the answer</b>: cherry-picking a pleasing answer is not verification.</span><span class='qd'><b>Trust the most confident-sounding response</b>: confidence is not a measure of accuracy.</span>" },
  { id:"D3-089", domain:3, obj:"3.1", diff:"hard", q:"A beginner insists, 'If the AI gives me a source link, the claim is verified.' Which correction is MOST accurate?", options:["A link automatically verifies any claim it is attached to","Links from AI are never useful for anything","Only a broken link indicates a problem","The link only helps if you open it and confirm it is real and actually supports the claim"], answer:3, explain:"<strong>The link only helps if you open it and confirm it is real and actually supports the claim</strong>: a link is a lead to check, not proof, because it can be fake or unrelated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A link automatically verifies any claim it is attached to</b>: an unchecked link verifies nothing.</span><span class='qd'><b>Links from AI are never useful for anything</b>: links can be useful precisely when you follow and confirm them.</span><span class='qd'><b>Only a broken link indicates a problem</b>: a working link can still be fabricated or fail to support the claim.</span>" },
  { id:"D3-090", domain:3, obj:"3.2", diff:"medium", q:"You get conflicting information from an AI and a well-established authoritative source. The MOST reasonable default is to:", options:["Trust the AI over the established source","Assume both are equally wrong and give up","Lean toward the established authoritative source and investigate the discrepancy","Flip a coin to decide which to believe"], answer:2, explain:"<strong>Lean toward the established authoritative source and investigate the discrepancy</strong> is most reasonable: a vetted authority is generally more trustworthy than unverified AI output, and the gap deserves a look.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust the AI over the established source</b>: preferring unverified AI over a vetted authority is unjustified.</span><span class='qd'><b>Assume both are equally wrong and give up</b>: there is no basis to dismiss a reputable source outright.</span><span class='qd'><b>Flip a coin to decide which to believe</b>: randomly choosing ignores the difference in source credibility.</span>" },
  { id:"D3-091", domain:3, obj:"3.3", diff:"medium", q:"An AI gives advice that was accurate for an old version of a software product but is wrong for the current version released after its training cutoff. The user should FIRST:", options:["Assume the advice still applies today","Argue with the AI until it changes its answer","Check the current official release notes or documentation for the updated behavior","Give up on the task entirely"], answer:2, explain:"<strong>Check the current official release notes or documentation for the updated behavior</strong> is the right first move because current authoritative docs reflect changes the model could not know.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume the advice still applies today</b>: assuming stale advice is current can cause errors.</span><span class='qd'><b>Argue with the AI until it changes its answer</b>: arguing cannot supply information the model lacks.</span><span class='qd'><b>Give up on the task entirely</b>: the answer is readily available in current documentation.</span>" },
  { id:"D3-092", domain:3, obj:"3.4", diff:"hard", q:"A company wants ONE guiding principle that helps catch hallucinations, bias, slop, outdated info, and ethical risks all at once. Which principle BEST does this?", options:["Increase the AI's typing speed","Use a larger font for all AI text","Ask the AI to rate its own quality and trust that rating","Always keep a knowledgeable human reviewing AI output before it is trusted or published"], answer:3, explain:"<strong>Always keep a knowledgeable human reviewing AI output before it is trusted or published</strong> addresses all error types at once: a human in the loop can catch fabrication, bias, slop, stale facts, and ethical issues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase the AI's typing speed</b>: speed does nothing to catch content errors.</span><span class='qd'><b>Use a larger font for all AI text</b>: font size is irrelevant to accuracy or ethics.</span><span class='qd'><b>Ask the AI to rate its own quality and trust that rating</b>: self-rating is not independent and can be as flawed as the output.</span>" },
  { id:"D3-093", domain:3, obj:"3.1", diff:"medium", q:"An AI produces a detailed answer full of specific names, dates, and figures for a very obscure topic with almost no reliable public information. This pattern should make you:", options:["Trust it more because it is so detailed","Assume it must have interviewed experts","Publish it immediately to be first","Be extra cautious, since rich detail on data-scarce topics is a common hallucination signature"], answer:3, explain:"<strong>Be extra cautious, since rich detail on data-scarce topics is a common hallucination signature</strong>: abundant specifics where little real data exists often signals fabrication.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust it more because it is so detailed</b>: detail is not evidence, especially on obscure topics.</span><span class='qd'><b>Assume it must have interviewed experts</b>: the model does not interview anyone.</span><span class='qd'><b>Publish it immediately to be first</b>: publishing unverified detailed claims is risky.</span>" },
  { id:"D3-094", domain:3, obj:"3.2", diff:"medium", q:"'Probing the depth' of an AI answer means:", options:["Making the text longer for no particular reason","Deleting half of the answer to test it","Reading the answer out loud","Testing whether it truly understands by asking for reasoning, examples, or edge cases"], answer:3, explain:"<strong>Testing whether it truly understands by asking for reasoning, examples, or edge cases</strong>: depth-probing checks if the model can support and defend its claim, not just state it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Making the text longer for no particular reason</b>: adding length does not test understanding.</span><span class='qd'><b>Deleting half of the answer to test it</b>: removing content tests nothing.</span><span class='qd'><b>Reading the answer out loud</b>: reading aloud does not probe the model's reasoning.</span>" },
  { id:"D3-095", domain:3, obj:"3.3", diff:"hard", q:"A company must decide whether to let an AI tool auto-publish content with no human review. The BIGGEST content-quality argument for keeping a human reviewer is that AI can:", options:["Type faster than humans can","Change fonts automatically","Produce hallucinations, bias, or generic slop that a human can catch before publication","Never make any mistakes at all"], answer:2, explain:"<strong>Produce hallucinations, bias, or generic slop that a human can catch before publication</strong> is the biggest reason: a human reviewer intercepts the very error types AI is prone to.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Type faster than humans can</b>: speed is not a reason to keep a reviewer.</span><span class='qd'><b>Change fonts automatically</b>: font handling is irrelevant to content quality review.</span><span class='qd'><b>Never make any mistakes at all</b>: AI does make mistakes, which is precisely why review is needed.</span>" },
  { id:"D3-096", domain:3, obj:"3.4", diff:"medium", q:"You ask an AI to 'summarize the report' but paste no report and give no title, and it produces a confident summary anyway. What likely happened?", options:["It correctly summarized your report","It refused to answer without the report","It reached into your files automatically","It fabricated a summary because it lacked the actual context it needed"], answer:3, explain:"<strong>It fabricated a summary because it lacked the actual context it needed</strong> is what happened: with no report provided, the model invented plausible content to fill the gap.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It correctly summarized your report</b>: it could not summarize a report it never received.</span><span class='qd'><b>It refused to answer without the report</b>: the scenario states it produced a summary, so it did not refuse.</span><span class='qd'><b>It reached into your files automatically</b>: a chatbot does not silently reach into your files without being given them.</span>" },
  { id:"D3-097", domain:3, obj:"3.1", diff:"hard", q:"Which scenario BEST demonstrates that 'sounding authoritative' and 'being accurate' are not the same thing?", options:["An AI politely asks a clarifying question","An AI correctly summarizes text you pasted","An AI says it is unsure and suggests checking a source","An AI cites a precise-sounding law section number that, when looked up, does not exist"], answer:3, explain:"<strong>An AI cites a precise-sounding law section number that, when looked up, does not exist</strong> perfectly shows the gap: the authoritative-sounding citation is fabricated.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An AI politely asks a clarifying question</b>: asking for clarification is helpful and involves no false authority.</span><span class='qd'><b>An AI correctly summarizes text you pasted</b>: an accurate summary is a case of being right, not falsely authoritative.</span><span class='qd'><b>An AI says it is unsure and suggests checking a source</b>: expressing uncertainty is the opposite of false authority.</span>" },
  { id:"D3-098", domain:3, obj:"3.2", diff:"medium", q:"A student uses AI to draft a research summary and then confirms each claim against reliable sources, corrects two errors, and keeps the rest. This overall approach BEST demonstrates:", options:["Blindly trusting the AI output","Using AI as a first draft while verifying before relying on it","Refusing to use AI at all","Publishing without any checks"], answer:1, explain:"<strong>Using AI as a first draft while verifying before relying on it</strong> is the healthy pattern: the AI accelerates the work, and human verification ensures accuracy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Blindly trusting the AI output</b>: the student verified and corrected errors, which is not blind trust.</span><span class='qd'><b>Refusing to use AI at all</b>: the student did use AI, so this does not describe the approach.</span><span class='qd'><b>Publishing without any checks</b>: the student checked each claim, the opposite of no checks.</span>" },
  { id:"D3-099", domain:3, obj:"3.3", diff:"hard", q:"A publisher wants a single review question that flags the widest range of AI error types (fabrication, bias, staleness, and ethical issues). Which question BEST does this?", options:["'What color scheme should we use?'","'Is every claim accurate, fair, current, and free of privacy or copyright problems, verified against reliable sources?'","'How many words is this piece?'","'Did the AI respond quickly enough?'"], answer:1, explain:"<strong>'Is every claim accurate, fair, current, and free of privacy or copyright problems, verified against reliable sources?'</strong> is best because it simultaneously targets fabrication, bias, outdated info, and ethical risks in one check.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>'What color scheme should we use?'</b>: aesthetics do not address any content error type.</span><span class='qd'><b>'How many words is this piece?'</b>: length says nothing about accuracy, fairness, or ethics.</span><span class='qd'><b>'Did the AI respond quickly enough?'</b>: speed is a performance metric, not a content-quality check.</span>" },
  { id:"D3-100", domain:3, obj:"3.4", diff:"hard", q:"You must present an AI-provided market figure to executives tomorrow, and it is plausible. Applying a plausibility-and-risk assessment, which action is MOST appropriate?", options:["Assume plausible means proven and present it as fact","Delete it because all AI figures are wrong","Verify the figure against an authoritative source given the high stakes, and label it if it cannot be confirmed","Round it to a memorable number and move on"], answer:2, explain:"<strong>Verify the figure against an authoritative source given the high stakes, and label it if it cannot be confirmed</strong> is most appropriate: high-stakes figures warrant verification, and any unconfirmed number should be clearly flagged rather than presented as fact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assume plausible means proven and present it as fact</b>: plausibility is not proof, especially for an executive decision.</span><span class='qd'><b>Delete it because all AI figures are wrong</b>: not all AI figures are wrong; verification, not blanket rejection, is the right move.</span><span class='qd'><b>Round it to a memorable number and move on</b>: altering an unverified figure makes it less accurate, not more trustworthy.</span>" }
);
